{
        Instance storage inst = _getInstance(instanceId);
        ActionEvent storage ev = inst.events[EventKey.StartEvent_1];
        require(ev.exists, "event not set");
        require(ev.state == ElementState.ENABLED, "event state not allowed");

        ev.state = ElementState.COMPLETED;
        emit ActionEventDone(instanceId, EventKey.StartEvent_1);
        inst.gateways[GatewayKey.ParallelGateway_1].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Message storage m = inst.messages[MessageKey.MsgA];
        require(m.exists, "message not set");
        _checkParticipant(inst, m.sendParticipant);
        require(m.state == ElementState.ENABLED, "message state not allowed");

        m.fireflyTranId = fireflyTranId;
        m.state = ElementState.COMPLETED;
        emit MessageSent(instanceId, MessageKey.MsgA, fireflyTranId);
        inst.gateways[GatewayKey.ParallelGateway_2].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Message storage m = inst.messages[MessageKey.MsgB];
        require(m.exists, "message not set");
        _checkParticipant(inst, m.sendParticipant);
        require(m.state == ElementState.ENABLED, "message state not allowed");

        m.fireflyTranId = fireflyTranId;
        m.state = ElementState.COMPLETED;
        emit MessageSent(instanceId, MessageKey.MsgB, fireflyTranId);
        inst.gateways[GatewayKey.ParallelGateway_2].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Message storage m = inst.messages[MessageKey.MsgC];
        require(m.exists, "message not set");
        _checkParticipant(inst, m.sendParticipant);
        require(m.state == ElementState.ENABLED, "message state not allowed");

        m.fireflyTranId = fireflyTranId;
        m.state = ElementState.COMPLETED;
        emit MessageSent(instanceId, MessageKey.MsgC, fireflyTranId);
        inst.events[EventKey.EndEvent_1].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Gateway storage g = inst.gateways[GatewayKey.ParallelGateway_1];
        require(g.exists, "gateway not set");
        require(g.state == ElementState.ENABLED, "gateway state not allowed");

        g.state = ElementState.COMPLETED;
        emit GatewayDone(instanceId, GatewayKey.ParallelGateway_1);
        inst.messages[MessageKey.MsgA].state = ElementState.ENABLED;
        inst.messages[MessageKey.MsgB].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        Gateway storage g = inst.gateways[GatewayKey.ParallelGateway_2];
        require(g.exists, "gateway not set");
        require(g.state == ElementState.ENABLED, "gateway state not allowed");

        g.state = ElementState.COMPLETED;
        emit GatewayDone(instanceId, GatewayKey.ParallelGateway_2);
        if (!(inst.messages[MessageKey.MsgA].state == ElementState.COMPLETED && inst.messages[MessageKey.MsgB].state == ElementState.COMPLETED)) {
                    revert("Parallel gateway prerequisites not met");
                }
        inst.messages[MessageKey.MsgC].state = ElementState.ENABLED;

    }

{
        Instance storage inst = _getInstance(instanceId);
        ActionEvent storage ev = inst.events[EventKey.EndEvent_1];
        require(ev.exists, "event not set");
        require(ev.state == ElementState.ENABLED, "event state not allowed");

        ev.state = ElementState.COMPLETED;
        emit ActionEventDone(instanceId, EventKey.EndEvent_1);

    }
